INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '20ccaeeb-8461-4bfd-8c83-281279339981',
  '00000000-0000-0000-0000-000000000001',
  $escape$Svelte's $derived — When Memoization Helps and When It's Overkill$escape$,
  $escape$Svelte 5 uses `$derived` (and `$derived.by` for complex logic) as its memoization primitive — it caches a computed value and only recomputes when its reactive dependencies change. Unlike React's `useMemo`, you don't manually declare a dependency array; Svelte's compiler tracks them automatically.

Where it pays off: expensive computations over large arrays, filtered/sorted lists derived from state, or values read in multiple places. Without `$derived`, each read would re-execute the expression on every render pass.

Where it hurts: wrapping trivial expressions like `$derived(count + 1)` adds overhead — the proxy tracking and cache lookup cost more than just computing inline. Similarly, `$derived` on a value used only once in the template offers zero benefit.

In Svelte 4, `$: computed = heavyFn(data)` was the equivalent — reactive statements memoized by the compiler. Svelte 5's `$derived` makes the intent explicit and composes better in class-based or `.svelte.ts` rune files. Reach for it when the computation is non-trivial or the derived value fans out to multiple consumers.$escape$,
  $escape$// Svelte 5 — worth memoizing: expensive filter over large list
let items = $state<Item[]>(rawData);
let query = $state('');

// $derived caches; recomputes only when items or query change
let filtered = $derived(
  items.filter(i => i.title.toLowerCase().includes(query.toLowerCase()))
);

// NOT worth memoizing: trivial expression used once
// let label = $derived(count + ' items'); // overkill — just inline it

// $derived.by for multi-step logic
let ranked = $derived.by(() => {
  const scores = filtered.map(i => ({ ...i, score: rank(i) }));
  return scores.sort((a, b) => b.score - a.score);
});$escape$,
  $escape$typescript$escape$,
