INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '882d9e7e-ad82-44d4-a915-4d3c340b6184',
  '00000000-0000-0000-0000-000000000001',
  $escape$Svelte Code Quality — eslint-plugin-svelte, Naming Conventions, and the 50-Line Rule$escape$,
  $escape$Svelte has no react-hooks plugin to worry about, but eslint-plugin-svelte fills the gap with rules purpose-built for reactive code. Enable `svelte/no-unused-svelte-ignore`, `svelte/valid-compile`, and `svelte/no-reactive-reassign` — the last one catches the classic mistake of reassigning a `$:`-derived variable and expecting reactivity to follow. For naming, Svelte enforces its own grammar: component files must be PascalCase (`UserCard.svelte`), writable stores should use a noun (`userStore`, not `fetchUser`), and the `$` prefix is reserved for store auto-subscription — never prefix plain variables with it or you'll confuse the compiler. Event handlers live in the script block and follow `handleX` (e.g., `handleSubmit`), not inline arrow functions, which breaks reactivity tracing in Svelte 5 runes mode. Apply the 50-line rule to the `<script>` block specifically: if your script exceeds 50 lines, extract logic into a `.svelte.ts` module using `$state` and `$derived` runes. This keeps the component declarative and the logic independently testable.$escape$,
  $escape$// eslint.config.js
import sveltePlugin from 'eslint-plugin-svelte';
import svelteParser from 'svelte-eslint-parser';

export default [
  {
    files: ['**/*.svelte'],
    languageOptions: { parser: svelteParser },
    plugins: { svelte: sveltePlugin },
    rules: {
      'svelte/no-unused-svelte-ignore': 'error',
      'svelte/no-reactive-reassign': 'error',
      'svelte/valid-compile': 'error',
      'svelte/no-at-debug-tags': 'warn',
    },
  },
];$escape$,
  $escape$javascript$escape$,
