INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '15796f0a-6569-408c-97f7-e415ef3965da',
  '00000000-0000-0000-0000-000000000001',
  $escape$Svelte WebSockets — Singleton Connection, Reconnection, and Optimistic UI with Runes$escape$,
  $escape$A singleton WebSocket in Svelte 5 lives in a `.svelte.ts` module — a plain TypeScript file where runes are valid. Declare the socket and message state at module scope so every component importing the file shares the same connection instance, not one per mount.

For reconnection, attach an `onclose` handler that schedules `connect()` via `setTimeout`. Add exponential backoff by tracking retry count. Guard against infinite loops during HMR by checking `socket.readyState` before reconnecting.

Optimistic UI on send is clean with Svelte 5's deeply reactive `$state`: push the message as `{ text, confirmed: false }` before calling `socket.send()`. Because `$state` tracks mutations on arrays and objects, `messages.push()` triggers reactive updates automatically — no spread, no reassignment. When the server echoes back confirmation, find the pending entry by ID and flip `confirmed` to `true`.

Components import `messages` and `send` directly. Use `{#each messages as m}` to render. No per-component `onMount`/`onDestroy` socket wiring — the module handles lifecycle once at import time, keeping component code lean.$escape$,
  $escape$// ws.svelte.ts — shared singleton across all components
let socket: WebSocket | null = null;
export const messages = $state<{ id: string; text: string; confirmed: boolean }[]>([]);

function connect() {
  socket = new WebSocket('wss://api.example.com/ws');
  socket.onmessage = (e) => {
    const { id } = JSON.parse(e.data);
    const msg = messages.find(m => m.id === id);
    if (msg) msg.confirmed = true;
  };
  socket.onclose = () => setTimeout(connect, 2000);
}
connect();

export function send(text: string) {
  const id = crypto.randomUUID();
  messages.push({ id, text, confirmed: false }); // optimistic
  socket?.send(JSON.stringify({ id, text }));
}$escape$,
  $escape$typescript$escape$,
