INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'cf8ab915-b003-469f-8098-f933ff97e19f',
  '00000000-0000-0000-0000-000000000001',
  $escape$Svelte API Layer — One HTTP Client, Interceptors, Zero Raw Fetches in Components$escape$,
  $escape$Svelte components should never call `fetch` directly. Scatter raw fetches across `.svelte` files and you lose centralized auth injection, retry logic, and error normalization overnight.

The pattern: one `$lib/api.ts` module exports a typed `api` object. Internally, a single `request()` function reads the auth token from a Svelte store via `get(authToken)` — synchronous, no subscription overhead — then attaches the `Authorization` header to every call. On a 401, the function retries once with the latest token value before surfacing an error.

In any `+page.svelte` or `load()` function, import `api` and call `api.get<T>('/bytes')`. The component stays clean. Token rotation, base URL config, and error shape all live in one file.

For SvelteKit `load()` functions running on the server, thread the `fetch` from `LoadEvent` into `request()` instead of the global — SvelteKit's `fetch` carries cookies and avoids port conflicts during SSR. Expose it as an optional parameter.

Result: zero raw fetches in components, automatic auth headers, and a single seam to attach OpenTelemetry spans or structured error logging.$escape$,
  $escape$// $lib/api.ts
import { get } from 'svelte/store';
import { authToken } from '$lib/stores/auth';

async function request<T>(path: string, init: RequestInit = {}, retries = 1, fetcher = fetch): Promise<T> {
  const res = await fetcher(`/api${path}`, {
    ...init,
    headers: { Authorization: `Bearer ${get(authToken)}`, 'Content-Type': 'application/json', ...init.headers },
  });
  if (res.status === 401 && retries > 0) return request<T>(path, init, retries - 1, fetcher);
  if (!res.ok) throw new Error(await res.text());
  return res.json() as Promise<T>;
}

export const api = {
  get: <T>(path: string, fetcher?: typeof fetch) => request<T>(path, {}, 1, fetcher),
  post: <T>(path: string, body: unknown) => request<T>(path, { method: 'POST', body: JSON.stringify(body) }),
};$escape$,
  $escape$typescript$escape$,
