INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '93378ac7-ccb2-483e-8dbc-163385889b40',
  '00000000-0000-0000-0000-000000000001',
  $escape$Svelte Global UI Patterns — Toast, Modal, and Confirmation Dialogs Done Right$escape$,
  $escape$Global UI like toasts and modals belongs in `+layout.svelte`, not scattered across routes. The idiomatic SvelteKit pattern: create module-level state that acts as a shared event bus, mount the UI at the root layout, call the functions anywhere.

For confirmation dialogs, go further — a promise-based approach turns `confirm()` into an awaitable call usable inside any event handler. Export an `ask(message)` function that stores the message alongside its `Promise` resolver. The `<ConfirmDialog>` mounted in your layout calls `respond(true|false)` on user action, which unblocks the awaiting caller. No component coupling, no callback props.

For toasts, a `$state` array in a `.svelte.ts` file with auto-dismiss via `setTimeout` is sufficient — push from any module, subscribe reactively in the layout.

Svelte 5's `.svelte.ts` rune files are the right home for this shared state: `$state` gives you fine-grained reactivity without writable store boilerplate, and the module is importable everywhere. Mount once in `+layout.svelte`, call from any route, action, or server response handler — zero prop drilling, zero context threading.$escape$,
  $escape$// $lib/confirm.svelte.ts
type Pending = { message: string; resolve: (ok: boolean) => void } | null;

let pending = $state<Pending>(null);

export const confirmDialog = {
  get pending() { return pending; },
  ask(message: string) {
    return new Promise<boolean>((resolve) => {
      pending = { message, resolve };
    });
  },
  respond(ok: boolean) {
    pending?.resolve(ok);
    pending = null;
  },
};$escape$,
  $escape$typescript$escape$,
