INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a3ae3ea5-66ca-4d20-84c1-49d4d5272ae2',
  '00000000-0000-0000-0000-000000000001',
  $escape$Svelte in Production — Sentry Error Capture, Web Vitals, and Source Maps$escape$,
  $escape$`@sentry/sveltekit` provides SvelteKit-aware error capture through `hooks.client.ts`. Exporting `handleError = Sentry.handleErrorWithSentry()` catches unhandled errors that reach SvelteKit's error boundary — including failed `load` functions and uncaught promise rejections triggered during navigation.

Source maps wire up via `sentrySvelteKit()` added to the `plugins` array in `vite.config.ts`. The plugin auto-uploads maps during `vite build` using `SENTRY_AUTH_TOKEN` — no separate CLI upload step needed. Set `sourceMapsUploadOptions.org` and `.project` to match your Sentry project slug.

For Web Vitals, call `onCLS`, `onLCP`, and `onINP` from the `web-vitals` package inside `onMount` in your root `+layout.svelte`. Each callback fires when the browser finalises the metric; forward it to Sentry via `captureEvent` at `level: 'info'` to keep vitals out of your error quota. SvelteKit's client-side routing means CLS and LCP accumulate across soft navigations — tag each event with `$page.url.pathname` from `$app/stores` for per-route breakdown in Sentry dashboards.$escape$,
  $escape$// hooks.client.ts
import * as Sentry from '@sentry/sveltekit';
Sentry.init({ dsn: import.meta.env.PUBLIC_SENTRY_DSN, tracesSampleRate: 0.1 });
export const handleError = Sentry.handleErrorWithSentry();

// +layout.svelte <script>
import { onMount } from 'svelte';
import { page } from '$app/stores';
import { onCLS, onLCP, onINP } from 'web-vitals';

onMount(() => {
  [onCLS, onLCP, onINP].forEach(fn =>
    fn(({ name, value }) =>
      Sentry.captureEvent({ message: `vital:${name}`, level: 'info', extra: { value, route: $page.url.pathname } })
    )
  );
});$escape$,
